import React from 'react';
import { View, Text, Image, TouchableOpacity, ScrollView } from 'react-native';
import styles, { colors } from '../styles';

const logo = require('../assets/logo.png');

export default function Dashboard({ navigation }: any) {
  const upcoming = [
    { id: '1', title: 'Casamento: Ana & João', date: '2026-05-15', location: 'Igreja Matriz' },
    { id: '2', title: 'Chá de bebê: Marina', date: '2026-06-02', location: 'Espaço Aurora' },
  ];

  const formatDate = (iso: string) => {
    try { return new Date(iso).toLocaleDateString('pt-BR'); } catch { return iso; }
  };

  return (
    <ScrollView style={styles.page} contentContainerStyle={{ padding: 16 }}>
      <View style={{ alignItems: 'center', marginBottom: 18 }}>
        <Image source={logo} style={{ width: 88, height: 88 }} resizeMode="contain" />
        <Text style={{ fontSize: 20, fontWeight: '700', marginTop: 8 }}>Casaki</Text>
        <Text style={{ color: colors.muted, marginTop: 4 }}>Gerencie seus eventos e lista de presentes</Text>
      </View>

      <Text style={styles.sectionTitle}>Próximos eventos</Text>
      {upcoming.map((e) => (
        <TouchableOpacity key={e.id} style={styles.card} onPress={() => navigation.navigate('EventoDetail', { id: e.id })}>
          <View style={styles.cardIconRow}>
            <View style={[styles.cardIcon, { backgroundColor: '#EFEBFF' }]}>
              <Text style={styles.cardIconText}>🎉</Text>
            </View>
            <View style={{ flex: 1, marginLeft: 12 }}>
              <Text style={styles.cardTitle}>{e.title}</Text>
              <Text style={styles.cardMeta}>{formatDate(e.date)} • {e.location}</Text>
            </View>
          </View>
        </TouchableOpacity>
      ))}

      <Text style={[styles.sectionTitle, { marginTop: 8 }]}>Ações rápidas</Text>
      <TouchableOpacity style={styles.card} onPress={() => navigation.navigate('CadastroEventos')}>
        <View style={styles.cardIconRow}>
          <View style={[styles.cardIcon, { backgroundColor: '#FFF3E8' }]}>
            <Text style={styles.cardIconText}>＋</Text>
          </View>
          <View style={{ flex: 1, marginLeft: 12 }}>
            <Text style={styles.cardTitle}>Criar evento</Text>
            <Text style={styles.cardMeta}>Adicionar novo evento manualmente</Text>
          </View>
        </View>
      </TouchableOpacity>

    </ScrollView>
  );
}
